import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Button, Input, Select, Pagination, StatusBadge, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { hrService } from '../../../services/ns/hrService';
import type { EmployeeDto, EmployeeType } from '../../../services/ns/models';
import styles from '../../../styles/erpPage.module.css';
import { ListSearchRefreshButtons } from '../../../components/list/ListSearchRefreshButtons';

const PAGE_SIZE = 20;

const TYPE_OPTIONS = [
  { value: '', label: 'Tất cả loại HĐ' },
  { value: 'TimeContract', label: 'Thời gian' },
  { value: 'PieceRate', label: 'Khoán' },
  { value: 'Seasonal', label: 'Thời vụ' },
];

const ACTIVE_OPTIONS = [
  { value: '', label: 'Tất cả trạng thái' },
  { value: 'true', label: 'Hoạt động' },
  { value: 'false', label: 'Nghỉ việc' },
];

const TYPE_LABELS: Record<EmployeeType, string> = {
  TimeContract: 'Thời gian',
  PieceRate: 'Khoán',
  Seasonal: 'Thời vụ',
};

const NhanVienListPage: React.FC = () => {
  const [reloadKey, setReloadKey] = useState(0);
  const dispatch = useAppDispatch();
  const navigate = useNavigate();

  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [type, setType] = useState('');
  const [activeFilter, setActiveFilter] = useState('');
  const [currentPage, setCurrentPage] = useState(1);

  const [items, setItems] = useState<EmployeeDto[]>([]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [deleteConfirmId, setDeleteConfirmId] = useState<string | null>(null);
  const [deleting, setDeleting] = useState(false);
  const handleSearch = () => setSearch(searchDraft.trim());
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      hrService.getEmployees({
        search: search || undefined,
        type: type || undefined,
        isActive: activeFilter === '' ? undefined : activeFilter === 'true',
        page: currentPage,
        pageSize: PAGE_SIZE,
      })
        .then(res => {
          if (!cancelled) {
            setItems(res.items);
            setTotalCount(res.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled)
            dispatch(addToast({ message: err?.message ?? 'Lỗi tải danh sách nhân viên', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [search, type, activeFilter, currentPage, reloadKey]);

  const handleDelete = async (id: string) => {
    setDeleting(true);
    try {
      await hrService.deleteEmployee(id);
      dispatch(addToast({ message: 'Xóa nhân viên thành công', type: 'success' }));
      setDeleteConfirmId(null);
      setCurrentPage(p => p);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    } finally {
      setDeleting(false);
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-users" /> Danh mục nhân viên</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={() => navigate('/ns/nhan-vien/them')}>
            <i className="fas fa-plus" /> Thêm nhân viên
          </Button>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`erp-nhan-vien-filters`}>
        <Input
          placeholder="Tìm theo mã, tên..."
          value={search}
          onChange={e => { setSearch(e.target.value); setCurrentPage(1); }}
          size="small"
        />
        <Select
          value={type}
          onChange={e => { setType(e.target.value); setCurrentPage(1); }}
          options={TYPE_OPTIONS}
          size="small"
        />
        <Select
          value={activeFilter}
          onChange={e => { setActiveFilter(e.target.value); setCurrentPage(1); }}
          options={ACTIVE_OPTIONS}
          size="small"
        />
        <ListSearchRefreshButtons testIdPrefix="erp-nhan-vien" onSearch={handleSearch} onRefresh={refresh} showSearch={true} />
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : items.length === 0 ? (
          <div className={styles.empty}><i className="fas fa-inbox" /><p>Không có nhân viên</p></div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã NV</th>
                  <th>Họ và tên</th>
                  <th>Loại HĐ</th>
                  <th>Đơn vị</th>
                  <th>Tổ</th>
                  <th>Trạng thái</th>
                  <th className={styles.colActions}></th>
                </tr>
              </thead>
              <tbody>
                {items.map(r => (
                  <tr key={r.id}>
                    <td>
                      <button type="button" className={styles.codeLink} onClick={() => navigate(`/ns/nhan-vien/${r.id}`)}>
                        <code>{r.code}</code>
                      </button>
                    </td>
                    <td>{r.fullName}</td>
                    <td><span className={styles.tagDefault}>{TYPE_LABELS[r.type as EmployeeType] ?? r.type}</span></td>
                    <td>{r.departmentName ?? '—'}</td>
                    <td>{r.teamName ?? '—'}</td>
                    <td><StatusBadge status={r.isActive ? 'Active' : 'Inactive'} /></td>
                    <td className={styles.colActions}>
                      <button type="button" className={styles.actionBtn} onClick={() => navigate(`/ns/nhan-vien/${r.id}`)} title="Sửa">
                        <i className="fas fa-edit" />
                      </button>
                      {deleteConfirmId === r.id ? (
                        <>
                          <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} disabled={deleting} onClick={() => handleDelete(r.id)} title="Xác nhận xóa">
                            <i className="fas fa-check" />
                          </button>
                          <button type="button" className={styles.actionBtn} onClick={() => setDeleteConfirmId(null)} title="Huỷ">
                            <i className="fas fa-times" />
                          </button>
                        </>
                      ) : (
                        <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => setDeleteConfirmId(r.id)} title="Xóa">
                          <i className="fas fa-trash" />
                        </button>
                      )}
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        {totalCount > 0 && (
          <div className={styles.paginationRow}>
            <span className={styles.totalCount}>Tổng: {totalCount} nhân viên</span>
            <Pagination
              currentPage={currentPage}
              totalPages={Math.ceil(totalCount / PAGE_SIZE)}
              totalCount={totalCount}
              pageSize={PAGE_SIZE}
              onPageChange={setCurrentPage}
            />
          </div>
        )}
      </div>
    </div>
  );
};

export default NhanVienListPage;
